t.script:
document.addEventListener('DOMContentLoaded', function() {
    const container = document.getElementById('interview_slots_container');
    if (!container) return;
    const scheduleId = container.dataset.scheduleId;

    const busService = (window.odoo && window.odoo.__session_info__ && window.odoo.__session_info__.bus_service)
        || (window.__owl__ && window.__owl__.app && window.__owl__.app.env && window.__owl__.app.env.services && window.__owl__.app.env.services.bus_service);

    if (busService) {
        console.log('Subscribing to interview_slots_' + scheduleId);
        busService.addChannel('interview_slots_' + scheduleId);
        busService.addEventListener('notification', ({ detail }) => {
            for (const { type, payload } of detail) {
                if (type === 'slot_update' && payload.schedule_id == scheduleId) {
                    updateSlotUI(payload);
                }
            }
        });
    }
});

function updateSlotUI(data) {
    [1, 2, 3].forEach(slot => {
        const remaining = data['slot_' + slot + '_remaining'];
        const badge = document.querySelector(`.slot-badge[data-slot="${slot}"]`);
        const radio = document.getElementById('slot_' + slot);
        const option = document.querySelector(`.slot-option[data-slot="${slot}"]`);

        if (badge) {
            badge.textContent = remaining + ' chỗ trống';
            if (remaining <= 0) {
                badge.classList.remove('bg-success');
                badge.classList.add('bg-danger');
            } else {
                badge.classList.remove('bg-danger');
                badge.classList.add('bg-success');
            }
        }

        if (radio) {
            if (remaining <= 0) {
                radio.disabled = true;
                if (radio.checked) radio.checked = false;
            } else {
                radio.disabled = false;
            }
        }

        if (option) {
            if (remaining <= 0) {
                option.style.opacity = '0.5';
            } else {
                option.style.opacity = '1';
            }
        }
    });
}

const documentTypeEl = document.getElementById('x_id_document_type');
const documentNumberEl = document.getElementById('x_id_number');
const documentHintEl = document.getElementById('x_id_number_hint');

function updateDocumentValidationByType() {
    if (!documentTypeEl || !documentNumberEl) {
        return;
    }

    const isPassport = documentTypeEl.value === 'passport';
    if (isPassport) {
        documentNumberEl.setAttribute('pattern', '[A-Za-z0-9]{6,12}');
        documentNumberEl.setAttribute('minlength', '6');
        documentNumberEl.setAttribute('maxlength', '12');
        documentNumberEl.removeAttribute('inputmode');
        documentNumberEl.setAttribute('title', 'Hộ chiếu chỉ gồm chữ và số, độ dài từ 6 đến 12 ký tự');
        if (documentHintEl) {
            documentHintEl.textContent = 'Nếu chọn Hộ chiếu, vui lòng nhập chữ và số, độ dài từ 6 đến 12 ký tự.';
        }
    } else {
        documentNumberEl.setAttribute('pattern', '[0-9]{12}');
        documentNumberEl.setAttribute('minlength', '12');
        documentNumberEl.setAttribute('maxlength', '12');
        documentNumberEl.setAttribute('inputmode', 'numeric');
        documentNumberEl.setAttribute('title', 'CCCD phải gồm đúng 12 chữ số');
        if (documentHintEl) {
            documentHintEl.textContent = 'Nếu chọn CCCD, vui lòng nhập đúng 12 chữ số.';
        }
    }
}

if (documentTypeEl && documentNumberEl) {
    updateDocumentValidationByType();
    documentTypeEl.addEventListener('change', updateDocumentValidationByType);
}
